appsmith.onReady(() => {
  const model = appsmith.model;
  if (model && model.networkData) {
    renderDashboard(model.networkData, model.persona || "Adult");
  }
});
appsmith.onModelChange(newModel => {
  if (newModel && newModel.networkData) {
    renderDashboard(newModel.networkData, newModel.persona || "Adult");
  }
});
function renderDashboard(data, persona) {
  const domainList = document.getElementById('domain-list');
  const harvesterList = document.getElementById('harvester-list');
  const personaBadge = document.getElementById('persona-badge');
  const scoreElement = document.getElementById('overall-score');
  if (domainList) domainList.innerHTML = "";
  if (harvesterList) harvesterList.innerHTML = "";
  const currentPersona = persona || "Adult";
  const isMinor = currentPersona.toLowerCase().includes("minor");
  if (personaBadge) {
    personaBadge.textContent = `Persona: ${currentPersona}`;
    personaBadge.style.background = isMinor ? "linear-gradient(135deg, #6c5ce7 0%, #a29bfe 100%)" : "linear-gradient(135deg, #3498db 0%, #85c1e9 100%)";
  }
  if (scoreElement) {
    let score = data.fingerprintingScore || 0;
    if (isMinor && score > 0.1) score = Math.min(1.0, score * 2.5);
    scoreElement.textContent = score.toFixed(2);
    scoreElement.parentElement.style.background = score > 0.4 ? "linear-gradient(135deg, #e74c3c 0%, #c0392b 100%)" : "linear-gradient(135deg, #3498db 0%, #2980b9 100%)";
  }

  // Top Level Stats
  document.getElementById('total-domains').textContent = (data.domains || []).length;
  document.getElementById('tracker-count').textContent = (data.trackers || []).length;
  const httpsTraffic = data.traffic && data.traffic.httpsTraffic !== undefined ? data.traffic.httpsTraffic : 0;
  const httpsElement = document.getElementById('https-status');
  if (httpsElement) {
    httpsElement.textContent = (httpsTraffic * 100).toFixed(0) + "%";
    httpsElement.className = httpsTraffic >= 1 ? "value text-safe" : "value text-critical";
  }
  const postCount = data.traffic && data.traffic.post ? data.traffic.post.length : 0;
  const postEl = document.getElementById('request-ratio');
  if (postEl) {
    postEl.textContent = postCount;
    postEl.className = postCount > 0 ? "value text-critical" : "value text-safe";
  }
  const leakKb = data.preVerificationLeakKb || 0;
  const ageGateEl = document.getElementById('age-gate-status');
  if (ageGateEl) {
    ageGateEl.textContent = leakKb > 0 ? "Exposure Signal" : "Robust";
    ageGateEl.className = leakKb > 0 ? "value text-critical" : "value text-safe";
  }
  document.getElementById('pre-verify-leak').textContent = `${leakKb} KB Leaked`;

  // 1. Render Left Column (Egress Point Risk Analysis)
  if (domainList && data.details && data.details.length > 0) {
    const aiGiants = ['Google LLC', 'Meta', 'Microsoft', 'Amazon', 'OpenAI'];
    data.details.forEach(item => {
      const isFMP = aiGiants.includes(item.owner);
      let riskLevel = "Low Signal";
      let riskClass = "safe";
      const fingerprintingLevel = isMinor ? (item.fingerprinting || 0) * 2 : item.fingerprinting || 0;
      if (fingerprintingLevel >= 3 || isMinor && isFMP) {
        riskLevel = "CRITICAL SIGNAL";
        riskClass = "critical";
      } else if (fingerprintingLevel >= 2) {
        riskLevel = "High Signal";
        riskClass = "warning";
      }
      const evidence = (item.cookies || 0).toFixed(3);
      const categories = (item.categories || []).map(c => c.replace('Tracking', 'Harvesting')).join(', ') || 'Unknown Data Activity';
      const ownerDisplay = `${isFMP ? '⚠️ ' : ''}${item.owner || 'Unknown Entity'}`;
      const icon = riskClass === 'critical' ? '🔴' : riskClass === 'warning' ? '🟠' : '🟢';
      const div = document.createElement('div');
      div.className = 'list-item';
      div.innerHTML = `
                <div class="item-main">
                    <div class="item-icon">${icon}</div>
                    <div class="item-details">
                        <div class="item-title">${item.domain}</div>
                        <div class="item-meta"><strong>Owner:</strong> ${ownerDisplay} &bull; <strong>Activity:</strong> ${categories}</div>
                    </div>
                </div>
                <div class="item-actions">
                    <span class="status-badge ${riskClass}">${riskLevel}</span>
                    <span class="evidence-tag" title="Active Traces">${evidence} traces</span>
                </div>
            `;
      domainList.appendChild(div);
    });
  } else if (domainList) {
    domainList.innerHTML = `<div class="empty-state">No egress points detected.</div>`;
  }

  // 2. Render Right Column (Active Harvesters)
  if (harvesterList && data.trackers && data.trackers.length > 0) {
    data.trackers.slice(0, 10).forEach(t => {
      const div = document.createElement('div');
      div.className = 'list-item';
      div.innerHTML = `
                <div style="width: 100%;">
                    <div class="compact-title">Path: ${t.host}</div>
                    <div class="compact-url">${(t.url || "").substring(0, 90)}...</div>
                </div>
            `;
      harvesterList.appendChild(div);
    });
  } else if (harvesterList) {
    harvesterList.innerHTML = `<div class="empty-state">No active streams observed.</div>`;
  }
}

